import java.util.*;

// Solution class to check if arr1[] is a subset of arr2[]
class Solution {
    // Function to perform binary search to check if an element is present in the array
    public boolean bSearch(int elem, int[] arr, int n) {
        int start = 0;
        int end = n - 1;

        // Perform binary search
        while (start <= end) {
            int mid = (start + end) / 2;

            // If element is found, return true
            if (arr[mid] == elem)
                return true;

            // If the element is greater than mid, search in the right half
            else if (arr[mid] < elem)
                start = mid + 1;

            // If the element is smaller than mid, search in the left half
            else
                end = mid - 1;
        }
        return false; // If the element is not found
    }

    // Function to check if arr1[] is a subset of arr2[]
    public boolean isSubset(int[] arr1, int m, int[] arr2, int n) {

        // Sort arr2[] for efficient binary search
        Arrays.sort(arr2);

        // If arr1[] has more elements than arr2[], it cannot be a subset
        if (m > n) return false;

        // For each element in arr1[], check if it exists in arr2[]
        for (int i = 0; i < m; i++) {
            boolean present = bSearch(arr1[i], arr2, n); // Check if arr1[i] is present in arr2[]

            // If any element from arr1[] is not present in arr2[], return false
            if (!present) return false;
        }

        // If all elements of arr1[] are found in arr2[], return true
        return true;
    }
}

// Driver class to test the solution
public class Main {
    public static void main(String[] args) {
        // Initialize arrays
        int[] arr1 = {1, 3, 4, 5, 2};
        int[] arr2 = {2, 4, 3, 1, 7, 5, 15};

        // Calculate the sizes of the arrays
        int m = arr1.length;
        int n = arr2.length;

        // Create an instance of Solution class
        Solution solution = new Solution();

        // Call the isSubset function
        boolean ans = solution.isSubset(arr1, m, arr2, n);

        // Output the result
        if (ans) {
            System.out.println("arr1[] is a subset of arr2[]");
        } else {
            System.out.println("arr1[] is not a subset of arr2[]");
        }
    }
}

